INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098956e","title":"Ходячие мертвецы. Том 3. В безопасности за решёткой","author":"Роберт Киркман, Чарли Адлард, Клифф Ратбёрн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002032231/140/2d71/Robert_Kirkman_Charli_Adlard_Kliff_Ratbjorn__Hodyachie_mertvetsy._Tom_3._V_bezop.jpg","isbn":"978-5-91339-453-8","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"Ходячие мертвецы","genres":["Комиксы","манга","графические романы"],"annotation":"Третий том легендарной психологической саги Роберта Киркмана \"\"Ходячие мертвецы\"\" | Walking Dead на русском языке  о выживании в условиях суровой постапокалиптической реальности. Оригинальный комикс, взятый за основу для популярного телесериала \"\"Ходячие мертвецы\"\"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-09","rating":5,"review":"","added":9999726,"hdCover":""},{"id":"098956d","title":"Остров маньяков","author":"Аскольд Акишин,Андрей Плотник,Даниил Ветлужских,Григорий Старостин,Алексей Горбут,показать всех","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002915557/140/cce6/__Ostrov_manyakov.jpg","isbn":"","publisher":"Vicious Membrane","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Приготовьтесь к резне! Остров Маньяков открыт для всех, кому исполнилось 18 лет! Беспощадная резня растекается на 86 страницах этого запретного сборника, произведённого кончеными маньяками своего дела! Сборник хоррор-историй от отечественных авторов. Интересная задумка и тема раскрывается в первой истории сборника (состоящего из 3-ёх историй). Само название комикса прямо говорит читателю, что ему ожидать от истории. Над первой и самой большой аркой работали Андрей Плотник (сценарий) и Алексей Горбут (рисунок). Хорошо написанный и сдержанный сюжет позволяет взглянуть на остров под призмой людей, пытающихся спастись от маньяков и убраться с острова. Странные моменты в сюжете есть, из-за чего читать к середине уже странновато, но рисунок Горбута – это спасение на все времена. Моя любимая страница – начало комикса, где показан багрово-красный закат. море и деревня сверху. Пейзаж и антураж напоминает «Остаться в живых». Крепкая история, но в большой степени из-за самой концепции. Второй сюжет Григория Старостина и Петра Калмыкова намного хуже первой истории. Это буквально спин-офф, рассказывающий о быте маньяков. Единственное, что мне понравилось – это страница с отсылками на разных персонажей комиксов и литературы. Сюжет – бред и треш, рисунок – непривычный и странный, не понравился. Заключительная история от Даниила Ветлужских и Аскольда Акишина находится где-то посередине между первой и второй. Неплохая концепция, которую можно назвать игрой «Temple Run». Рисунок Акишина далеко не самый крутой, возможно, из-за цветовой гаммы. Всем историям чувствуется, что не хватает возможности раскрыться, так как весь сборник состоит из 86 страниц. Комикс преследует хорошая концепция, но реализацию подкачала. Свернуть","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-09","rating":3,"review":"","added":9999725,"hdCover":""},{"id":"098956c","title":"Драка!","author":"Джек Тигл","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002554132/140/e945/Dzhek_Tigl__Draka.jpg","isbn":"978-5-99093-619-5","publisher":"КомФедерация","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Парнишка Лю (сокращённое от Люцифера) - профессиональный реслер. Его карьера злобного Дьябло на высоте, сотни фанатов боёв без правил каждый четверг выстраиваются в километровые очереди, чтобы увидеть схватку Дьябло и светоокого Спасителя - \"хорошего парня\" по имени Джо, который всегда побеждает (как добро - зло). Но Лю своей работой недоволен, ведь и за пределами ринга он похож на… дьявола, краснокожего и с рогами. А значит \"сценическое амплуа\" преследует его везде - все так и норовят оскорбить и унизить \"коварного Дьябло\". Но в реальной жизни он очень добрый малый, любящий свою матушку и почитающий память отца. В конце концов Лю теряет терпение и принимает решение уйти из реслинга. Добьётся ли он уважения, которого заслуживает?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-09","rating":3,"review":"","added":9999724,"hdCover":""},{"id":"098956b","title":"Ходячие мертвецы. Том 2. Мили позади","author":"Роберт Киркман, Чарли Адлард, Клифф Ратбёрн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002032232/140/38f3/Robert_Kirkman_Charli_Adlard_Kliff_Ratbjorn__Hodyachie_mertvetsy._Tom_2._Mili_po.jpg","isbn":"978-5-91339-452-1","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"Ходячие мертвецы","genres":["Комиксы","манга","графические романы"],"annotation":"Сколько часов в день вы не тратите, просиживая перед телевизором? Когда в последний раз кто-нибудь из нас на самом деле старался, чтобы получить желаемое?  Давно ли кому-то из нас действительно было нужно то, чего мы постоянно хотим?  Мир, который мы знали, исчез.  На смену миру торговли и пустого потребительства пришел мир выживания и ответственности.  Эпидемия апокалиптических масштабов прокатилась по планете, пробудив мёртвых, которые начали пожирать живых.  За несколько месяцев человеческое общество было разрушено.  Исчезли правительства, магазины, доставка почты, кабельное телевидение.  В мире, где правят мёртвые, мы наконец вынуждены начать жить.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-09","rating":4.5,"review":"","added":9999723,"hdCover":""},{"id":"098956a","title":"Ходячие мертвецы. Том 1. Дни минувшие","author":"Роберт Киркман, Тони Мур","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002054655/140/fd86/Robert_Kirkman_Toni_Mur__Hodyachie_mertvetsy._Tom_1._Dni_minuvshie.jpg","isbn":"978-5-91339-451-4","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Сколько часов в день вы не тратите, просиживая перед телевизором?  Когда в последний раз кто-нибудь из нас на самом деле старался, чтобы получить желаемое?  Давно ли кому-то из нас действительно было нужно то, чего мы постоянно хотим?  Мир, который мы знали, исчез.  На смену миру торговли и пустого потребительства пришел мир выживания и ответственности.  Эпидемия апокалиптических масштабов прокатилась по планете, пробудив мёртвых, которые начали пожирать живых.  За несколько месяцев человеческое общество было разрушено.  Исчезли правительства, магазины, доставка почты, кабельное телевидение.  В мире, где правят мёртвые, мы наконец вынуждены начать жить.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-08","rating":4.5,"review":"","added":9999722,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989569","title":"Шерлок Франкенштейн и Легион Зла","author":"Джефф Лемир,Дэвид  Рубин","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002819275/140/b152/__Sherlok_Frankenshtejn_i_Legion_Zla.jpg","isbn":"978-5-91339-669-3","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"ЭТА ДЕТЕКТИВНАЯ ИСТОРИЯ ПРОИСХОДИТ В МИРЕ СУПЕРГЕРОЕВ! ЖУРНАЛИСТКА ПЫТАЕТСЯ УЗНАТЬ, ЧТО ЖЕ СЛУЧИЛОСЬ С ЕЁ ОТЦОМ - ЧЕРНЫМ МОЛОТОМ.  Все  ответы, которые дают бывшие суперзлодеи, а ныне пациенты печально известной психиатрической лечебницы Спираль-Сити, кажутся ложью. Подбираясь всё ближе к правде, она узнаёт мрачные истории происхождения самых знаменитых врагов Чёрного Молота, которые являются частью одной мозаики и могут пролить свет на то, что же всё-таки произошло.  Включает выпуски #1-4 серии «Шерлок Франкенштейн и Легион Зла» от Dark Horse Comics и выпуск #12 серии «Чёрны Молот»","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-08","rating":4,"review":"","added":9999721,"hdCover":""},{"id":"0989568","title":"Мешки (или история о них)","author":"Патрик МакХэйл,Гэвин Фуллертон","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003531255/140/2a24/__Meshki_ili_istoriya_o_nih.jpg","isbn":"978-5-04-108434-9","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"Пхандо - Даже если не любишь меня / Nareul saranhaji anhado","genres":["Комиксы","манга","графические романы"],"annotation":"Это история Джона Моттса. Он — человек, у которого была собака, но теперь эта собака пропала. Джон обыскивает свой дом, свою улицу, свой город, но его собаки, Бет, нигде нет. Джон быстро понимает, что должен идти дальше, мимо дороги и в лес, если хочет когда-нибудь узнать правду о том, что случилось с Бет. \"Мешки (или история о них)\" — это путешествие любви и ненависти, в котором Джон Моттс исследует мир известный и неизвестный, красиво сотканный Патриком МакХейлом, создателем удостоенного премии \"Эмми\" сериала Cartoon Network \"По ту сторону изгороди\", и Гэвином Фуллертоном (\"Космические цыплята в космосе\" от Disney). Комикс-адаптация первого романа Патрика МакХейла, работа над которым велась с многочисленными  перерывами из-за создания популярного мультисериала «По ту сторону изгороди» от Cartoon Network. Гэвин Фуллертон взялся адаптировать роман и нарисовать комикс, что получилось у него неимоверно качественно, мило и хорошо (сам роман я не читал, да и с автором познакомился впервые, но, скорее всего, Гэвин проделал и эту работу на отлично). Колористом выступила Уитни Когар, я считаю, что это и есть первая изюминка комикса – ярке цвета, выражающие всю суть происходящего на странице. Даже леттерер Мари Энгер сделала шрифт немного растянутым, подтёкшим, напоминающим нечто старое, забытое и ненужное. Также можно и охарактеризовать главного героя, хотя бы в начале комикса. Знакомьтесь, Джон Моттс! История о \"маленьком\" человеке, который не знаком и чужд другим горожанам такого же обыкновенного и типичного городка. У Джона есть собака Бет, которую он очень любит. Однажды днём во время обеденного перерыва Джон не находит Бет в доме и во дворе, поэтому отправляется на поиски своего питомца. Обыкновенное начало произведения, в котором главная задача героя – это поиски. Но сами похождения описаны не так, как можно себе представить. Джон проходит несколько этапов социализации по пути к заветной цели – обрести счастье и гармонию, которая была нарушена исчезновением по непонятной причине. У читателя во время ознакомления возникает диссонанс, когда он видит одно, а на деле оказывается другим. Метафоричность предметов видна по мере чтения и осознания \"сути\" происходящего. В городе люди выглядят совершенно обычно, кроме Джона, который изображён маленьким человечком с маленькими потребностями и идеалами в мире, а также знакомого \"мешочника\" – Моржа, постоянно перекладывающего свои вещи с места на место. Джон не хочет пышности и разнообразности, лишь маленькое успокоение и сохранение прежних устоев ежедневного быта. Джон идёт по тропе под названием \"жизнь\". На уступах он встречает других обитателей мира, выглядящих не так, как он, занимающихся другими делами. Проблема Джона заключается в его детской неприспособленности к обитанию, но в это же время замкнутость поддерживала в нём чувство жизни. Направляющим звеном в его жизни оказывается дикая волчица, которую Джон находит в лесу. Благодаря ей герой может адоптироваться и поменять ориентиры в жизни. Возможно он найдёт жизненный смысл в заботе за волчицей и снова будет замкнут задачами одного, но никто не будет говорить, что это плохо. Философский комикс оказывается, хотя при покупке ты об этом даже не задумываешься. Постраничное резюмирование идеально для формата адаптации. Даже эпилог в три истории представлен читателю, в котором виден флэшбэк о \"прошлом дне\" Джона и Бет, когда они были вместе (время абстрактно в комиксе, как и сами вещи, герои. следует расценивать \"время\" в роли подведения черты о моменте \"до\" и \"после\"). А также третья часть, где герой и волчица приходят из леса в город. Этот момент можно расценивать в виде проведения второй черты в жизни Джона, входящего в новую роль и меняющего жизненные приоритеты, несмотря на трудности прошлого. Герои уходят в закат! Финал очень многообещающий, надеюсь, что у Джона всё получится, и они вместе с волчицей будут счастливы. Само название «Мешки» может означать общее понятие пороков человека и его отношение к ним. Как говорит один из героев комикса – Морж: «Вот правда, что доступна мне – никогда нельзя… класть все свои вещи в один мешок. как нельзя и класть все свои вещи в разные мешки, так как это то же самое, что вообще не иметь мешков! Значит, нужно сортировать и пересортировывать, и сортировать снова. Всегда сортировать и всегда помнить, что нужно класть соотвествующие вещи а соответствующие мешки.» Человек в процессе жизни меняет ориентиры, двигаясь по вертикальной и горизонтальной лестницам социума, меняя и/ или обретая принципы, он буквально \"перекладывает\" собственное \"я\" из одного мешка в другой, закрывая тем самым прошлый период нахождения \"предмета\" в другом месте. Также нельзя совмещать всё вместе, ведь тогда потеряется суть сортирования. Это же и происходит с человеком, когда он смотрит на жизнь, не разделяя общих или конкретных предметов. Совсем не примечательный комикс на первый взгляд оказывается отличным произведением на полчаса, порождающий новые мысли и проводящий параллели с реальными действиями. Еженедельное обсуждение прочитанного в группе ВК                                                Свернуть","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-08","rating":4,"review":"","added":9999720,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
