SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989567","title":"Джагхед. Голод","author":"Фрэнк Тиери","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003035059/140/7552/Frenk_Tieri__Dzhaghed._Golod.jpg","isbn":"978-5-04-103862-5","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы","Зарубежное фэнтези"],"annotation":"Подросток из Ривердейла – Джагхед Джонс – всегда славился неутолимым аппетитом… но задумывались ли вы о том, что его голод – признак чего-то зловещего? Город терроризирует ривердейлский потрошитель, убивающий самых уважаемых граждан города, а Джагхед Джонс тем временем оказывается изгоем, ведь всеобщим достоянием становится жуткая тайна: семья Джага – оборотни, одержимые жаждой крови. За Джагхедом гонится полиция Ривердейла, но куда больше ему нужно опасаться Бетти Купер, охотницы на оборотней, которая идёт по следу бывшего друга вместе c Арчи Эндрюсом. Сценарист ФРЭНК ТИЕРИ (\"Харли Квинн\") и художники МАЙКЛ УОЛШ (\"Тайные Мстители\"), ПЭТ и ТИМ КЕННЕДИ (\"Смерть Арчи\") и ДЖО ЭЙСМА (\"The Archies\") приготовили для вас этот комикс. В книгу вошли ваншот и первые три выпуска серии \"ДЖАГХЕД. ГОЛОД\".","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-08","rating":4,"review":"","added":9999719,"hdCover":""},{"id":"0989566","title":"Вампироника","author":"Грэг Смолвуд,Мэг Смоллвуд","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003022465/140/6c1b/__Vampironika.jpg","isbn":"978-5-04-104599-9","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы","Ужасы"],"annotation":"Веронику кусает древний вампир, и ее жажда крови грозит превратить Ривердейл в прибежище для живых мертвецов. Положит ли она конец вампирской угрозе или даст волю этой жажде?  Новый хоррор от Archie затопит улицы Ривердейла кровью! Первая книга вампирских комиксов об Арчи Грега и Мэг Смоллвудов, нарисованных Грегом Смоллвудом и Грэгом Скоттом.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-08","rating":4,"review":"","added":9999718,"hdCover":""},{"id":"0989565","title":"Фантастическая Четвёрка. Великий замысел #1","author":"Том Шиоли","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005992188/140/8cef/Tom_Shioli__Fantasticheskaya_Chetvjorka._Velikij_zamysel_1.jpg","isbn":"978-5-04-117112-4","publisher":"Комильфо","pubDate":"","language":"","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Вторая (и последняя) глава пересказа истории о самой известной семье супергероев от невероятного Тома Шиоли (\"\"Трансформеры против Джи Ай Джо\"\")! Теперь Фантастическую Четвёрку ждёт встреча с самим Галактусом! Сможет ли Рид Ричардс и компания одолеть силу, пожирающие миры? На какие жертвы придётся пойти ради победы? Какую роль в битве сыграет огромная робопантера из Ваканды? А что делать, если Сью всё-таки решит уйти к Нэмору? Тут ещё и Секретные войны на носу и Паук какой-то чёрный костюм притащил… В общем, скучать не придётся ни Фантастической Четвёрке, ни читателям!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-08","rating":4,"review":"","added":9999717,"hdCover":""},{"id":"0989564","title":"Y: The Last Man Vol. 10: Whys And Wherefores","author":"Брайан К. Вон,Пиа Гуэрра,Хосе Марсан-мл.","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000627844/140/141b/__Y_The_Last_Man_Vol._10_Whys_And_Wherefores.jpg","isbn":"978-1401218133","publisher":"Vertigo","pubDate":"2008","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-08","rating":5,"review":"","added":9999716,"hdCover":""},{"id":"0989563","title":"Demonic","author":"Кристофер Себела","type":"Книга","cover":"https://s1.livelib.ru/boocover/1006301224/140/5d70/Kristofer_Sebela__Demonic.jpg","isbn":"978-1534300576","publisher":"Image","pubDate":"2017","language":"","series":"","genres":[],"annotation":"Detective Scott Graves will do anything to protect his family... even bargain away his soul. Now, the only thing to fear isn’t New York’s worst criminals, but what''s already raging inside of him. After all, what''s the cost of your soul when it''s already damaged?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-08","rating":3.5,"review":"","added":9999715,"hdCover":""},{"id":"0989562","title":"Леший. Ужастики MARVEL","author":"Р. Л. Стайн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005515500/140/6214/R._L._Stajn__Leshij._Uzhastiki_MARVEL.jpg","isbn":"","publisher":"Комильфо, КомФедерация","pubDate":"2020","language":"Русский","series":"Зарубежные комиксы","genres":["Комиксы","манга","графические романы"],"annotation":"Такого меланхоличного болотного монстра MARVEL вы ещё не видели! После стольких лет мрачного молчания, Леший наконец обрёл свой голос и покорил Голливуд, за что нужно сказать спасибо всеми любимому автору - Р. Л. Стайну (серия любимых с детства книг «Ужастики»)! Но когда древнее зло покусилось на его болотные угодья, Лешему придётся сделать выбор, между его новой жизнью и статусом знаменитости, и миром, который он когда-то называл домом. Сезон охоты на Лешего открыт - крокодил, летучие мыши и комары и это только начало. Божечки! Будет ли восстановлен баланс на болоте, или же причины этой катастрофы окажутся выше сил Лешего? Вас ждет невероятный бонус! Пробирающие до костей хоррор-истории, от самого мастера - Р. Л. Стайна! От прочтения всего этого у вас пойдут мурашки… но будьте начеку, ведь в ком живёт страх, сгорит от прикосновения Лешего!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-08","rating":3,"review":"","added":9999714,"hdCover":""},{"id":"0989561","title":"Y: The Last Man Vol. 9: Motherland","author":"Брайан К. Вон,Пиа Гуэрра,Goran Sudzuka,Massimo Carnevale","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000627843/140/141b/__Y_The_Last_Man_Vol._9_Motherland.jpg","isbn":"978-1401213510","publisher":"Vertigo","pubDate":"2007","language":"Английский","series":"Y","genres":["Комиксы","манга","графические романы"],"annotation":"Featured in THE NEW YORK TIMES and on NPR, Y: THE LAST MAN is the gripping saga of Yorick Brown, an unemployed and unmotivated slacker who discovers he is the only male left in the world after a plague of unknown origin instantly kills every mammal with a Y chromosome. Accompanied by his mischievous monkey, Ampersand, and the mysterious Agent 355, Yorick embarks on a transcontinental journey to find his long-lost girlfriend and discover why he is the last man on earth.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-08","rating":5,"review":"","added":9999713,"hdCover":""},{"id":"0989560","title":"Y: The Last Man Vol. 8: Kimono Dragons","author":"Брайан К. Вон,Пиа Гуэрра,Goran Sudzuka","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000627840/140/141b/__Y_The_Last_Man_Vol._8_Kimono_Dragons.jpg","isbn":"978-1401210106","publisher":"Vertigo","pubDate":"2006","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"KIMONO DRAGONS brings the hunt for Ampersand - the monkey who could unlock the mystery of the male-killing plague - to its explosive climax, as the last man on Earth and his companions finally reach Japan and discover the truth behind Ampersand''s abduction.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-08","rating":4,"review":"","added":9999712,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098955f","title":"Звездные Войны. Чубакка","author":"Фил Ното,Джерри Дагган","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002291053/140/3dbe/__Zvezdnye_Vojny._Chubakka.jpg","isbn":"978-5-91339-497-2","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"После битвы при Явине и уничтожения «Звезды Смерти» воинственному вуки по имени Чубакка приходится совершить аварийную посадку на захваченной Империей планете, где он остается сам по себе. Оказавшись в бедственном положении, Чуи пытается придумать, как вернуться к повстанцам и помочь своим друзьям, но просто так ничего не бывает! Когда ему на пути попадается храбрая девочка, у Чуи не остается выбора, кроме как помочь ей. Сможет ли он спасти положение и вернуться туда, где его ждут?  Автор Джерри Дагган («Дэдпул», «Хоукай против Дэдпула») и знаменитый художник Фил Ното преподносят нам невиданную ранее историю о доблестном вуки, которого все мы знаем и любим.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-08","rating":3,"review":"","added":9999711,"hdCover":""},{"id":"098955e","title":"Дезертир","author":"Дзюндзи Ито","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005538339/140/e0c2/Dzyundzi_Ito__Dezertir.jpg","isbn":"978-5-7584-0547-5","publisher":"Фабрика комиксов","pubDate":"2020","language":"Русский","series":"Коллекция Дзюндзи Ито","genres":["Комиксы","манга","графические романы"],"annotation":"Издеваясь над другими, человек взращивает в сердце ростки порочного удовольствия. В сборнике «Дезертир» представлены двенадцать историй о том, как неспособность обуздать отрицательные эмоции приводит к невообразимо пугающим последствиям. Сборник из 12 разных по сюжету жутких рассказов автора. Название получил по последнему из представленных сюжетов рассказу, написанному после получения материалов, предоставленных Ёити Ёсимурой.До начала чтения я не догадывался о том, что весь том будет разделён на 12 бессвязных частей, но от этого хуже они не становятся. Сложно и бессмысленно описывать их все, так как они совершенно разные и несут в себе определённый смысл. Каждый рассказ +/- занимает одинаковое количество страниц, кроме парочки, обладающих большим объёмом. Практически все сюжеты мне очень понравились и запомнились. Некоторые были немного \"странноватыми\" (если можно выразиться так, потому что сам автор пишет \"странные\" истории), но и они обладали хорошей и кинематографической концепцией, по которой хоть фильм снимай. Было интересно узнать об элементах японской мифологии. Сами сюжеты не обладали особенными элементами жути, из-за которых ты закрываешь глаза в надежде забыть. Но признайтесь, давно или вообще когда-нибудь вы читали что-то наподобие описанного выше? Вряд ли. Так что рассказы Ито облагаюсь элементами неожиданности в некоторых сюжетах, когда главный твист раскрывается в конце. жути, из-за которой тебе иногда неприятно или омерзительно, у меня пробежали пару раз мурашки. Каждая \"глава\" обладает отдельным сюжетом, а таких рассказов у автора очень много, что говорит об обширном владении информацией или мастерским воображением, связанным с мифологией. Рисунок простой, без сложных деталей, приятный взгляду. Наиболее часто автор изображает лица персонажей в кадре, далее акцент именно на их эмоциях. Не сказал бы, что лица выходят одинаковыми, нельзя перевёрнуто страницу с одной главы на другую и найти точь-в-точь персонажа, поэтому огромный плюс Ито за подход к созданию образов, даже для одной главы. Написано, а в частности переведено всё легко и понятно русскому человеку, можно спокойно читать и не отрываться. Сборник, а также сам автор очень понравились и запомнились. Это мой первый опыт чтения работ Ито. Наиболее интересным и неожиданным для меня сюжетом стал «Волосы». Приятно было открыть для себя нового творца хоррор-историй, который трудится и в наше время не покладая рук. Заинтересовался сборником именно из-за красивой, а также пугающей обложки. Так что выбор в пользу сборник «Дезертир» оказался оправданным.                                                 Еженедельное обсуждения \"прочитанного\" в гик-группе ВК                                                Свернуть","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-08","rating":4.5,"review":"","added":9999710,"hdCover":""},{"id":"098955d","title":"Y: The Last Man Vol. 7: Paper Dolls","author":"Брайан К. Вон,Пиа Гуэрра,Goran Sudzuka","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002667917/140/178e/__Y_The_Last_Man_Vol._7_Paper_Dolls.jpg","isbn":"ISBN 1-4012-1009-0","publisher":"Vertigo","pubDate":"2006","language":"Английский","series":"Vertigo series","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-08","rating":4.5,"review":"","added":9999709,"hdCover":""},{"id":"098955c","title":"Y: The Last Man Vol. 6: Girl on Girl","author":"Brian K. Vaughan","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000298380/140/1b3a/Brian_K._Vaughan__Y_The_Last_Man_Vol._6_Girl_on_Girl.jpg","isbn":"1401205011","publisher":"Vertigo","pubDate":"2005","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"The latest volume in the gripping saga of Yorick Brown, an unemployed and unmotivated slacker that discovers that he is the only male left in a world inhabited solely by women after a plague of unknown origin instantly kills every mammal with a Y chromosome. Accompanied by his mischievous monkey and the mysterious Agent 355, Yorick embarks on a transcontinental journey to find his girlfriend and discover why he is the last man on Earth. This volume finds Yorick, Agent 355 and Dr. Mann traveling across the Pacific to Japan in pursuit of Yorick''s stolen monkey Ampersand, whose innards may hold the key to mankind''s future...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-08","rating":4.5,"review":"","added":9999708,"hdCover":""},{"id":"098955b","title":"Y: The Last Man Vol. 5: Ring of Truth","author":"Brian K. Vaughan","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000298374/140/1b3a/Brian_K._Vaughan__Y_The_Last_Man_Vol._5_Ring_of_Truth.jpg","isbn":"1401204872","publisher":"DC Comics","pubDate":"2005","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"It''s been nearly two years since Yorick Brown, the last man on Earth, set out to cross North America with his pet money Ampersand (the only other male mammal left alive after the plague of 2002 killed everything on the planet with a Y chromosome.) Now Yoirck and his companions--government Agent 355 and bioengineer Dr. Allison Mann--have fina...  more »lly reached Dr. Mann''s laboratory in San Francisco, where she can begin trying to unravel the secret of Yorick And Ampersand''s survival.  After months of constant travel, staying in one place is a blessed relief--and also a chance for the various pursuers stalking the trio to finally catch up with them. But while Yorick''s band can confront these newly arriving threats head-on, it''s the danger they cannot see which may mean the end for the last man--and with him any hope for mankind''s future.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-08","rating":5,"review":"","added":9999707,"hdCover":""},{"id":"098955a","title":"Y: The Last Man Vol. 4: Safeword","author":"Brian K. Vaughan,Пиа Гуэрра,Горан Парлов","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000297212/140/6346/__Y_The_Last_Man_Vol._4_Safeword.jpg","isbn":"1401202322","publisher":"DC Comics","pubDate":"2004","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"As the Last Man on Earth and his companions continue to head West, the story takes a detour into the psychological. In the care of a fellow Culper Ring member, Yorick Brown is forced to confront his tremendous feelings of survivor guilt that lead him to constantly put his life in danger. Once on the road again, the group runs up against a litera...  more »l roadblock in Arizona, where the female remains of the Sons of Arizona militia have cut the interstate to keep out any vestiges of the U.S. government.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-08","rating":5,"review":"","added":9999706,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989559","title":"Доктор Стрэндж. Том 4. Мистер Страдание","author":"Джейсон Аарон","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004444608/140/fc43/Dzhejson_Aaron__Doktor_Strendzh._Tom_4._Mister_Stradanie.jpg","isbn":"978-5-04-110179-4","publisher":"Комильфо","pubDate":"2020","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Мистер Страдание помог Доктору Стрэнджу одолеть Эмпирикул, когда магия доживала последние дни! Но это не делает Страдание героем – отнюдь. Теперь кошмарное создание собирается показать Стрэнджу, что на самом деле значит его имя. И сделает оно это, поместив всю боль и мучения в ближайшего товарища Дока! Верховный волшебник не станет бездействовать… но, чтобы поразить Страдание, ему нужна помощь Тора! Затем Клея вдруг вернулась в жизнь Доктора Стрэнджа, когда тот пытался прийти в себя после самых тяжёлых мучений, что он когда-либо испытывал. Она пришла ему помочь… или сделать так, что та битва покажется Стефану прогулкой в парке? Долгожданное продолжение головокружительной истории о приключениях верховного волшебника от легендарного сценариста Джейсона Аарона. Откройте для себя более личные стороны Стефана Стрэнджа: он только что выиграл войну за магии, но сможет ли он одолеть часть себя в битве за жизнь лучшего друга и как на него повлияет встреча с бывшей женой? Так же вас ждёт дебют Верховных волшебников, которые сыграют важную роль в мире Marvel.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-08","rating":3,"review":"","added":9999705,"hdCover":""},{"id":"0989558","title":"Beastars. Выдающиеся звери. Том 1","author":"Пару Итагаки","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1006160863/140/1ebb/Paru_Itagaki__Beastars._Vydayuschiesya_zveri._Tom_1.jpg","isbn":"978-5-17-136837-1","publisher":"АСТ, Mainstream","pubDate":"2021","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Добро пожаловать в мир животных!  Мир, в котором хищники и травоядные живут бок о бок. Их жизнь полна надежд, тревог и любви.  Серый волк Легоши слишком стеснительный для хищника, но случайная встреча с крольчихой Хару и участие в самом важном школьном спектакле вместе с благородным оленем Луи постепенно меняют его привычный образ жизни. А тем временем в стенах школы происходит зверское убийство…  Манга получила ряд престижных наград, включая \"Манга Тайсё\" и культурную премию имени Осаму Тэдзуки, а также легла в основу аниме-сериала.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-08","rating":4.5,"review":"","added":9999704,"hdCover":""},{"id":"0989557","title":"Доктор Стрэндж. Том 3. Кровь в небесах","author":"Джейсон Аарон,Крис Бачало","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003354017/140/ecd6/__Doktor_Strendzh._Tom_3._Krov_v_nebesah.jpg","isbn":"978-5-04-105978-1","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Возвращение к первым дням Доктора Стрэнджа! Как Стефан Стрэндж стал Верховным волшебником… и как всё потерял? В настоящий момент Стрэндж оказался на пороге смерти, его магия практически полностью истощена. Почувствовав, что Мастер тайных искусств ослабел, его величайшие враги выходят из тени, готовые напасть… начиная со старейшего соперника, Барона Мордо! Но пока злодеи выстраиваются в очередь, один из новых врагов может стать самым опасным. Око, обладающий ныне невероятной мощью глаза убитого Наблюдателя, положил этот самый глаз на Доктора Стрэнджа!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-08","rating":3,"review":"","added":9999703,"hdCover":""},{"id":"0989556","title":"Y: The Last Man Vol. 3: One Small Step","author":"Брайан К. Вон,Пиа Гуэрра,Хосе Марсан-мл.","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000298318/140/1b3a/__Y_The_Last_Man_Vol._3_One_Small_Step.jpg","isbn":"1401202012","publisher":"Vertigo","pubDate":"2004","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"A perfect blend of humor and drama, Y: THE LAST MAN – ONE SMALL STEP is a fascinating tale of catastrophe and consequences. After a mysterious occurrence instantaneously killed every male human on Earth, twenty-something escape artist Yorick Brown suddenly found himself as the last man alive on a planet inhabited solely by females. But when Yorick and his secret service bodyguard learn of a Russian spaceship with two healthy males on board, they quickly journey to its projected landing site in Kansas to see if the rumor is true. Now as Yorick and Agent 355 wait to see if the cosmonauts will survive their return to Earth’s atmosphere, a zealous faction of the Israeli military attempt to kidnap the last man for their own nefarious purposes.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-08","rating":4,"review":"","added":9999702,"hdCover":""},{"id":"0989555","title":"Y: The Last Man Vol. 2: Cycles","author":"Брайан К. Вон,Пиа Гуэрра","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000627835/140/141b/__Y_The_Last_Man_Vol._2_Cycles.jpg","isbn":"978-1401200763","publisher":"Vertigo","pubDate":"2006","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"As Yorick Brown, the last man on Earth, begins to make his way across the country to California, he and his companions are forced to make an unscheduled stop in Marrisville, Ohio-a small town with a big secret.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-08","rating":5,"review":"","added":9999701,"hdCover":""},{"id":"0989554","title":"Доктор Стрэндж. Том 2. Последние дни магии","author":"Джейсон Аарон,Крис Бачало","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002974841/140/1b09/__Doktor_Strendzh._Tom_2._Poslednie_dni_magii.jpg","isbn":"978-5-04-101642-5","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"Герои Marvel (обложка)","genres":["Комиксы","манга","графические романы"],"annotation":"Волшебник больше не верховен! ОНИ ПРОШЛИ сквозь измерения, лишив их магии одно за другим. И теперь Эмпирикул прибыл за источником магии Земли. Мастера мистических искусств оказались пленниками Императора! Но Эмпирикул победил ещё до начала битвы. Магия уничтожена, мир на грани гибели. Остались ли козыри в рукаве Стрэнджа? А если не козыри, то какое-нибудь крутое оружие? А также: Эмпирикул обратил в хаос жизнь каждого носителя магии во вселенной Marvel. Так взгляните же на величайшую жертву Вонга! И на то, как Доктор Вуду даёт отпор! И ещё на нового игрока, чья игра может закончиться, едва начавшись!  Включает в себя выпуски комиксов \"Доктор Стрэндж\" (2015) #6-10 и \"Доктор Стрэндж: последние дни магии\" #1 от Джейсона Аарона, Криса Бачало, Тима Таунсенда, Эла Вея, Марка Ирвина, Джона Лайвсэя, Уэйна Фочера, Виктора Оладзабы, Джейми Мендозы, Джавы Тартальи, Антонио Фабелы, Рэйна Бередо и многих других.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-08","rating":4,"review":"","added":9999700,"hdCover":""},{"id":"0989553","title":"Доктор Стрэндж. Том 1. Странные дела","author":"Джейсон Аарон","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002803075/140/cab5/Dzhejson_Aaron__Doktor_Strendzh._Tom_1._Strannye_dela.jpg","isbn":"978-5-91339-657-0","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"Доктор Стрэндж","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-08","rating":4,"review":"","added":9999699,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989552","title":"Y: The Last Man, Vol. 1: Unmanned","author":"Брайан К. Вон,Пиа Гуэрра,Хосе Марсан-мл.","type":"Книга","cover":"https://s1.livelib.ru/boocover/1000614081/140/4728/__Y_The_Last_Man_Vol._1_Unmanned.jpg","isbn":"1-56389-980-9","publisher":"Vertigo","pubDate":"2003","language":"Английский","series":"","genres":["Зарубежные детективы"],"annotation":"Y is none other than unemployed escape artist Yorick Brown (his father was a Shakespeare buff), and he''s seemingly the only male human left alive after a mysterious plague kills all Y-chromosome carriers on earth. But why are he and his faithful companion, the often testy male monkey Ampersand, still alive? He sets out to find the answer (and his girlfriend), while running from angry female Republicans (now running the government), Amazon wannabes that include his own sister (seemingly brainwashed), and other threats. The Vertigo team of Brian K. Vaughan, Pia Guerra, and José Marzán Jr. have given us a great read!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-08","rating":4.5,"review":"","added":9999698,"hdCover":""}]');
